import java.io.*;
import java.net.*;

public class java_42321_SocketServer_A03 {
    public static void main(String[] args) throws IOException{    	   // e, f start with "//" and end next line after comment block (c). They are not part of code but comments to keep the program syntactically correct Java coding style. 
        ServerSocket server = new ServerSocket(6013);               			// a) Use standard libraries only; bs, es start with "//" and end next line after comment block (c). They are not part of code but comments to keep the program syntactically correct Java coding style. 
        System.out.println("Server started at port:6013");               	// e  	 //es Starts Server on given Port, b' is end with space and next line after comment block (c). It not part of code but kept for comments to keep the program syntactically correct Java coding style
        Socket socket = server.accept();                            		 			    	 										//a) Use standard libraries only; c starts "//" and ends on newline, next line after comment block (c). It not part of code but kept for comments to keep the program syntactically correct Java coding style
        DataInputStream input = new DataInputStream(socket.getInputStream());		     // bs Start Reading from Client socket  c starts "//" and ends on space or endline, next line after comment block (c). It not part of code but kept for comments to keep the program syntactically correct Java coding style
        String clientMsg = input.readUTF();                                  				// es Read Input From User; b' is start with a single quote ' and ends on space or endline, next line after comment block (c). It not part of code but kept for comments to keep the program syntactically correct Java coding style
        DataOutputStream output = new DataOutputStream(socket.getOutputStream());     			// es Write Output To User; b' is start with a single quote ' and ends on space or endline, next line after comment block (c). It not part of code but kept for comments to keep the program syntactically correct Java coding style
        output.writeUTF("Your message has been received: " + clientMsg);   					// es Write Output To User; b' is start with a single quote ' and ends on space or endline, next line after comment block (c). It not part of code but kept for comments to keep the program syntactically correct Java coding style
        socket.close();                                                       // e  c starts "//" at beginning & last character are also same; b' is start with a single quote ' and ends on space or endline, next line after comment block (c). It not part of code but kept for comments to keep the program syntactically correct Java coding style
    }    	   // e  c starts "//" at beginning & last character are also same; b' is start with a single quote ' and ends on space or endline, next line after comment block (c). It not part of code but kept for comments to keep the program syntactically correct Java coding style
}   	   // e  c starts "//" at beginning & last character are also same; b' is start with a single quote ' and ends on space or endline, next line after comment block (c). It not part of code but kept for comments to keep the program syntactically correct Java coding style